module top_module(
  input obf_in,
  input [n-1:0] sel,
  output [2**n-1:0] out
);parameter n = 3; // number of control signals

assign out[0] = sel == 0 ? obf_in : 0;
assign out[1] = sel == 1 ? obf_in : 0;
assign out[2] = sel == 2 ? obf_in : 0;
assign out[3] = sel == 3 ? obf_in : 0;
assign out[4] = sel == 4 ? obf_in : 0;
assign out[5] = sel == 5 ? obf_in : 0;
assign out[6] = sel == 6 ? obf_in : 0;
assign out[7] = sel == 7 ? obf_in : 0;

endmodule
